import React, { useState, useEffect } from 'react';
import { supabase } from '../supabaseClient';
import { useAuth } from '../contexts/AuthContext';

export default function AdminPanel() {
  const { profile, isAdmin } = useAuth();
  const [invitations, setInvitations] = useState([]);
  const [teamMembers, setTeamMembers] = useState([]);
  const [inviteEmail, setInviteEmail] = useState('');
  const [loading, setLoading] = useState(false);
  const [copiedToken, setCopiedToken] = useState(null);
  const [activeTab, setActiveTab] = useState('invite');

  useEffect(() => {
    if (isAdmin) {
      fetchInvitations();
      fetchTeamMembers();
    }
  }, [isAdmin]);

  async function fetchInvitations() {
    const { data } = await supabase
      .from('invitations')
      .select('*')
      .order('created_at', { ascending: false });
    setInvitations(data || []);
  }

  async function fetchTeamMembers() {
    const { data } = await supabase
      .from('profiles')
      .select('*')
      .order('full_name');
    setTeamMembers(data || []);
  }

  async function handleInvite(e) {
    e.preventDefault();
    setLoading(true);
    try {
      const { data, error } = await supabase
        .from('invitations')
        .insert({
          email: inviteEmail.toLowerCase().trim(),
          invited_by: profile.id,
        })
        .select()
        .single();

      if (error) throw error;

      setInviteEmail('');
      fetchInvitations();
      alert(`Invitation created! Share this token with ${data.email}:\n\n${data.token}`);
    } catch (err) {
      alert('Error: ' + err.message);
    } finally {
      setLoading(false);
    }
  }

  function copyToken(token) {
    navigator.clipboard.writeText(token);
    setCopiedToken(token);
    setTimeout(() => setCopiedToken(null), 2000);
  }

  async function handleRoleChange(userId, newRole) {
    await supabase.from('profiles').update({ role: newRole }).eq('id', userId);
    fetchTeamMembers();
  }

  if (!isAdmin) {
    return (
      <div style={styles.page}>
        <div style={styles.accessDenied}>
          <h2>Admin Access Required</h2>
          <p>You don't have permission to view this page.</p>
        </div>
      </div>
    );
  }

  return (
    <div style={styles.page}>
      <h1 style={styles.pageTitle}>Admin Panel</h1>
      <p style={styles.pageSubtitle}>Manage your team and invitations</p>

      {/* Tabs */}
      <div style={styles.tabs}>
        <button
          onClick={() => setActiveTab('invite')}
          style={{ ...styles.tab, ...(activeTab === 'invite' ? styles.tabActive : {}) }}
        >Invite Members</button>
        <button
          onClick={() => setActiveTab('team')}
          style={{ ...styles.tab, ...(activeTab === 'team' ? styles.tabActive : {}) }}
        >Team ({teamMembers.length})</button>
      </div>

      {activeTab === 'invite' && (
        <>
          {/* Invite Form */}
          <div style={styles.card}>
            <h3 style={styles.cardTitle}>Send Invitation</h3>
            <form onSubmit={handleInvite} style={styles.inviteForm}>
              <input
                type="email"
                value={inviteEmail}
                onChange={(e) => setInviteEmail(e.target.value)}
                placeholder="colleague@company.com"
                required
                style={styles.input}
              />
              <button type="submit" disabled={loading} style={styles.inviteBtn}>
                {loading ? 'Sending...' : 'Create Invite'}
              </button>
            </form>
            <p style={styles.helpText}>
              An invitation token will be generated. Share it with the person so they can sign up.
            </p>
          </div>

          {/* Pending Invitations */}
          <div style={styles.card}>
            <h3 style={styles.cardTitle}>Invitations</h3>
            {invitations.length === 0 ? (
              <p style={styles.emptyText}>No invitations sent yet.</p>
            ) : (
              <div style={styles.inviteList}>
                {invitations.map(inv => {
                  const isExpired = new Date(inv.expires_at) < new Date();
                  const isAccepted = !!inv.accepted_at;
                  return (
                    <div key={inv.id} style={styles.inviteItem}>
                      <div style={styles.inviteInfo}>
                        <div style={styles.inviteEmail}>{inv.email}</div>
                        <div style={styles.inviteMeta}>
                          Created {new Date(inv.created_at).toLocaleDateString()}
                          {' · '}
                          {isAccepted
                            ? <span style={{ color: '#22c55e' }}>Accepted</span>
                            : isExpired
                              ? <span style={{ color: '#ef4444' }}>Expired</span>
                              : <span style={{ color: '#f59e0b' }}>Pending</span>
                          }
                        </div>
                      </div>
                      {!isAccepted && !isExpired && (
                        <button
                          onClick={() => copyToken(inv.token)}
                          style={styles.copyBtn}
                        >
                          {copiedToken === inv.token ? '✓ Copied' : 'Copy Token'}
                        </button>
                      )}
                    </div>
                  );
                })}
              </div>
            )}
          </div>
        </>
      )}

      {activeTab === 'team' && (
        <div style={styles.card}>
          <h3 style={styles.cardTitle}>Team Members</h3>
          <div style={styles.teamList}>
            {teamMembers.map(member => (
              <div key={member.id} style={styles.teamItem}>
                <div style={styles.teamAvatar}>
                  {member.full_name?.charAt(0)?.toUpperCase()}
                </div>
                <div style={styles.teamInfo}>
                  <div style={styles.teamName}>
                    {member.full_name}
                    {member.id === profile.id && (
                      <span style={styles.youBadge}>You</span>
                    )}
                  </div>
                  <div style={styles.teamMeta}>
                    {member.email} · {member.title || 'No title set'}
                  </div>
                </div>
                <select
                  value={member.role}
                  onChange={(e) => handleRoleChange(member.id, e.target.value)}
                  disabled={member.id === profile.id}
                  style={styles.roleSelect}
                >
                  <option value="member">Member</option>
                  <option value="admin">Admin</option>
                </select>
              </div>
            ))}
          </div>
        </div>
      )}
    </div>
  );
}

